#include <stdio.h>
#include <string.h>

int main() {
    int n;
    scanf("%d", &n);
    char s[100000];
    scanf("%s", s);
    int count = 0;
    for (int i = 0; i < strlen(s); i++) {
        count++;
        if (s[i] == '0') {
            break;
        }
    }
    printf("%d\n", count);
    return 0;
}
